pub fn get_attachment_rules(name: &str) -> Option<AttachmentRules> {
    match name {
        "image" => Some(AttachmentRules {
            allowed: vec![
                "image/jpeg".to_string(),
                "image/png".to_string(),
                "image/webp".to_string(),
                "image/gif".to_string(),
            ],
            resize: Some(ResizeRule {
                width: Some(1920),
                height: Some(1080),
                quality: Some(82),
            }),
        }),
        _ => None,
    }
}


